// Solution
function orderMediaQueries(mediaQueries) {
    let features = mediaQueries.map(query => query.split(',').map(feature => feature.trim()));
    let sortedQueries = mediaQueries.sort((a, b) => {
        let aFeatures = a.split(',').map(feature => feature.trim()).sort().join(',');
        let bFeatures = b.split(',').map(feature => feature.trim()).sort().join(',');
        if (a.split(',').length !== b.split(',').length) {
            return a.split(',').length - b.split(',').length;
        } else {
            return aFeatures.localeCompare(bFeatures);
        }
    });
    return sortedQueries;
}

