class Solution:
    def orderMediaQueries(self, mediaQueries):
        features = [query.split(',') for query in mediaQueries]
        sortedQueries = sorted(mediaQueries, key=lambda query: (
            -len(query.split(',')),
            query.split(',').map(feature => feature.strip()).sort().join(',')
        ))
        return sortedQueries
